import React from 'react';
import { ICONS } from '../constants';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: ICONS.Dashboard },
    { id: 'devices', label: 'Devices', icon: ICONS.Zap },
    { id: 'guide', label: 'Architecture & Guide', icon: ICONS.Code },
    { id: 'settings', label: 'Settings', icon: ICONS.Settings },
  ];

  return (
    <div className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col h-screen sticky top-0">
      <div className="p-6">
        <div className="flex items-center gap-3 text-emerald-400">
          <ICONS.Zap />
          <h1 className="text-xl font-bold tracking-tight text-white">Sentinel Pro</h1>
        </div>
        <p className="text-xs text-slate-500 mt-1 uppercase font-semibold">IoT Monitoring</p>
      </div>

      <nav className="flex-1 px-4 space-y-2">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
              activeTab === item.id
                ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
                : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
            }`}
          >
            <item.icon />
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <div className="bg-slate-800/50 rounded-xl p-4">
          <p className="text-xs text-slate-400 mb-2">Backend Status</p>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-sm font-medium text-emerald-500">Connected</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { ChartData } from '../types';

interface ChartPanelProps {
  data: ChartData[];
  title: string;
  metric: string;
  color: string;
}

const ChartPanel: React.FC<ChartPanelProps> = ({ data, title, metric, color }) => {
  return (
    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-sm">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-lg font-semibold text-slate-200">{title}</h3>
        <div className="flex gap-2">
          <span className="text-xs font-medium px-2 py-1 bg-slate-800 rounded text-slate-400">Real-time</span>
        </div>
      </div>
      <div className="h-[300px] w-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis 
              dataKey="time" 
              stroke="#64748b" 
              fontSize={12} 
              tickLine={false} 
              axisLine={false}
            />
            <YAxis 
              stroke="#64748b" 
              fontSize={12} 
              tickLine={false} 
              axisLine={false}
              domain={['auto', 'auto']}
            />
            <Tooltip 
              contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
              itemStyle={{ color: '#f8fafc' }}
            />
            <Legend />
            <Line 
              type="monotone" 
              dataKey="Living Room" 
              stroke="#10b981" 
              strokeWidth={3} 
              dot={false}
              animationDuration={300}
            />
            <Line 
              type="monotone" 
              dataKey="Bedroom" 
              stroke="#3b82f6" 
              strokeWidth={3} 
              dot={false}
              animationDuration={300}
            />
            <Line 
              type="monotone" 
              dataKey="Kitchen" 
              stroke="#f59e0b" 
              strokeWidth={3} 
              dot={false}
              animationDuration={300}
            />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default ChartPanel;

import React, { useState } from 'react';

const ArchitectureGuide: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'esp32' | 'backend'>('overview');

  const esp32Code = `
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>

// WiFi & MQTT Credentials
const char* ssid = "YOUR_WIFI_SSID";
const char* password = "YOUR_WIFI_PASSWORD";
const char* mqtt_server = "YOUR_HIVEMQ_URL"; // e.g. xxxx.hivemq.cloud
const int mqtt_port = 8883;

WiFiClientSecure espClient;
PubSubClient client(espClient);

void setup() {
  Serial.begin(115200);
  setup_wifi();
  // ... Configure SSL/TLS ...
  client.setServer(mqtt_server, mqtt_port);
}

void loop() {
  if (!client.connected()) reconnect();
  client.loop();

  // Send data every 5 seconds
  static unsigned long lastMsg = 0;
  if (millis() - lastMsg > 5000) {
    lastMsg = millis();

    StaticJsonDocument<200> doc;
    doc["id"] = "esp32-livingroom";
    doc["temp"] = random(20, 25);
    doc["humidity"] = random(40, 60);

    char buffer[256];
    serializeJson(doc, buffer);
    client.publish("home/sensors/livingroom", buffer);
  }
}
  `.trim();

  const backendCode = `
const mqtt = require('mqtt');
const WebSocket = require('ws');
const sqlite3 = require('sqlite3').verbose();

// 1. Database Setup
const db = new sqlite3.Database('./iot_data.db');
db.serialize(() => {
  db.run("CREATE TABLE IF NOT EXISTS readings (id TEXT, temp REAL, humidity REAL, time DATETIME)");
});

// 2. MQTT Subscription
const mqttClient = mqtt.connect('mqtts://YOUR_HIVEMQ_URL', {
  username: 'your_user',
  password: 'your_password'
});

mqttClient.on('connect', () => {
  mqttClient.subscribe('home/sensors/#');
});

// 3. WebSocket Server
const wss = new WebSocket.Server({ port: 8080 });

mqttClient.on('message', (topic, message) => {
  const data = JSON.parse(message.toString());

  // Store in DB
  db.run("INSERT INTO readings VALUES (?, ?, ?, ?)", 
    [data.id, data.temp, data.humidity, new Date().toISOString()]);

  // Push to Frontend
  wss.clients.forEach(client => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(JSON.stringify(data));
    }
  });
});
  `.trim();

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header>
        <h2 className="text-3xl font-bold text-white mb-2">Architectural Blueprint</h2>
        <p className="text-slate-400">Step-by-step implementation for your student project.</p>
      </header>

      <div className="flex gap-4 border-b border-slate-800">
        {(['overview', 'esp32', 'backend'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-3 font-medium capitalize transition-colors ${
              activeTab === tab ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl">
            <h3 className="text-xl font-bold text-white mb-6">System Flow</h3>
            <div className="space-y-6">
              {[
                { step: 1, title: 'Edge (ESP32)', desc: 'Sensors read data and publish to MQTT via WiFi.' },
                { step: 2, title: 'Cloud (Broker)', desc: 'HiveMQ Cloud acts as the central hub for all traffic.' },
                { step: 3, title: 'Local Backend', desc: 'Node.js server subscribes to MQTT and pushes to WebSockets.' },
                { step: 4, title: 'Frontend', desc: 'React Dashboard displays real-time updates instantly.' }
              ].map(item => (
                <div key={item.step} className="flex gap-4">
                  <div className="w-8 h-8 rounded-full bg-emerald-500/10 text-emerald-400 flex items-center justify-center shrink-0 border border-emerald-500/20 font-bold">
                    {item.step}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-200">{item.title}</h4>
                    <p className="text-sm text-slate-400">{item.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 border border-slate-800 p-8 rounded-2xl">
            <h3 className="text-xl font-bold text-white mb-6">Free Hosting Stack</h3>
            <ul className="space-y-4">
              <li className="flex justify-between items-center p-3 bg-slate-800/50 rounded-lg">
                <span className="text-slate-200 font-medium">MQTT Broker</span>
                <span className="px-2 py-1 bg-blue-500/10 text-blue-400 text-xs rounded border border-blue-500/20 font-bold">HiveMQ Cloud (Free)</span>
              </li>
              <li className="flex justify-between items-center p-3 bg-slate-800/50 rounded-lg">
                <span className="text-slate-200 font-medium">Local Database</span>
                <span className="px-2 py-1 bg-emerald-500/10 text-emerald-400 text-xs rounded border border-emerald-500/20 font-bold">SQLite (Zero Cost)</span>
              </li>
              <li className="flex justify-between items-center p-3 bg-slate-800/50 rounded-lg">
                <span className="text-slate-200 font-medium">Frontend Hosting</span>
                <span className="px-2 py-1 bg-purple-500/10 text-purple-400 text-xs rounded border border-purple-500/20 font-bold">Vercel / Netlify</span>
              </li>
            </ul>
            <div className="mt-8 p-4 bg-amber-500/10 border border-amber-500/20 rounded-xl">
              <p className="text-sm text-amber-200">
                <strong>Pro-tip:</strong> Use <code>ngrok</code> if you want to access your local Node.js server from the public internet.
              </p>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'esp32' && (
        <div className="bg-slate-950 border border-slate-800 rounded-2xl overflow-hidden">
          <div className="p-4 bg-slate-900 border-b border-slate-800 flex justify-between items-center">
            <span className="text-xs font-mono text-slate-400 uppercase">iot_device.ino</span>
            <button className="text-xs text-emerald-400 font-bold hover:underline">Copy Code</button>
          </div>
          <pre className="p-6 overflow-x-auto mono text-sm text-emerald-300 bg-[#0c121e]">
            {esp32Code}
          </pre>
        </div>
      )}

      {activeTab === 'backend' && (
        <div className="bg-slate-950 border border-slate-800 rounded-2xl overflow-hidden">
          <div className="p-4 bg-slate-900 border-b border-slate-800 flex justify-between items-center">
            <span className="text-xs font-mono text-slate-400 uppercase">server.js (Node.js)</span>
            <button className="text-xs text-emerald-400 font-bold hover:underline">Copy Code</button>
          </div>
          <pre className="p-6 overflow-x-auto mono text-sm text-emerald-300 bg-[#0c121e]">
            {backendCode}
          </pre>
        </div>
      )}
    </div>
  );
};

export default ArchitectureGuide;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChartPanel from './components/ChartPanel';
import ArchitectureGuide from './components/ArchitectureGuide';
import { ICONS } from './constants';
import { ChartData, SensorData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [history, setHistory] = useState<ChartData[]>([]);
  const [latestData, setLatestData] = useState<Record<string, SensorData>>({
    'Living Room': { id: 'lr-1', room: 'Living Room', temp: 22.4, humidity: 45, light: 800, timestamp: new Date().toLocaleTimeString() },
    'Bedroom': { id: 'br-1', room: 'Bedroom', temp: 20.1, humidity: 50, light: 200, timestamp: new Date().toLocaleTimeString() },
    'Kitchen': { id: 'k-1', room: 'Kitchen', temp: 24.8, humidity: 40, light: 950, timestamp: new Date().toLocaleTimeString() },
  });

  // Simulation loop to mimic WebSocket traffic
  useEffect(() => {
    const interval = setInterval(() => {
      const rooms = ['Living Room', 'Bedroom', 'Kitchen'];
      const updatedData = { ...latestData };
      const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });

      rooms.forEach(room => {
        const prev = updatedData[room];
        updatedData[room] = {
          ...prev,
          temp: +(prev.temp + (Math.random() - 0.5) * 0.5).toFixed(1),
          humidity: Math.max(0, Math.min(100, +(prev.humidity + (Math.random() - 0.5) * 2).toFixed(1))),
          timestamp: now
        };
      });

      setLatestData(updatedData);

      setHistory(prev => {
        const newPoint: ChartData = {
          time: now,
          'Living Room': updatedData['Living Room'].temp,
          'Bedroom': updatedData['Bedroom'].temp,
          'Kitchen': updatedData['Kitchen'].temp,
        };
        const newHistory = [...prev, newPoint];
        return newHistory.slice(-20); // Keep last 20 points
      });
    }, 3000);

    return () => clearInterval(interval);
  }, [latestData]);

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight">System Overview</h2>
          <p className="text-slate-400">Monitoring 3 active ESP32 nodes across your environment.</p>
        </div>
        <div className="flex gap-3">
          <button className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-xl border border-slate-700 transition-all flex items-center gap-2">
            <ICONS.Settings />
            Manage Nodes
          </button>
        </div>
      </header>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <ICONS.Temp />
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Average Temp</p>
          <div className="flex items-baseline gap-2">
            <span className="text-4xl font-bold text-white">
              {(Object.values(latestData).reduce((a, b) => a + b.temp, 0) / 3).toFixed(1)}°C
            </span>
          </div>
          <div className="mt-4 flex items-center gap-2 text-emerald-400 text-xs font-bold">
            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
            Optimal Range
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <ICONS.Humidity />
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Humidity Avg</p>
          <div className="flex items-baseline gap-2">
            <span className="text-4xl font-bold text-white">
              {(Object.values(latestData).reduce((a, b) => a + b.humidity, 0) / 3).toFixed(0)}%
            </span>
          </div>
          <div className="mt-4 flex items-center gap-2 text-blue-400 text-xs font-bold">
            <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
            Healthy Levels
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <ICONS.Light />
          </div>
          <p className="text-slate-400 text-sm font-medium mb-1">Ambient Light</p>
          <div className="flex items-baseline gap-2">
            <span className="text-4xl font-bold text-white">
              {(Object.values(latestData).reduce((a, b) => a + b.light, 0) / 3).toFixed(0)}
            </span>
            <span className="text-slate-500 font-medium">lux</span>
          </div>
          <div className="mt-4 flex items-center gap-2 text-amber-400 text-xs font-bold">
            <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>
            Daylight Mode
          </div>
        </div>
      </div>

      {/* Main Graph Area */}
      <ChartPanel 
        data={history} 
        title="Temperature Variation (Last 20 Samples)" 
        metric="temp" 
        color="#10b981" 
      />

      {/* Device Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden">
          <div className="p-6 border-b border-slate-800 flex justify-between items-center">
            <h3 className="font-bold text-white">Node Health</h3>
            <span className="text-xs text-slate-500">Last heartbeat 2s ago</span>
          </div>
          <div className="divide-y divide-slate-800">
            {Object.values(latestData).map((device) => (
              <div key={device.room} className="p-4 flex items-center justify-between hover:bg-slate-800/30 transition-colors">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-emerald-400">
                    <ICONS.Zap />
                  </div>
                  <div>
                    <h4 className="text-sm font-bold text-slate-200">{device.room}</h4>
                    <p className="text-xs text-slate-500">ID: {device.id}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-mono text-emerald-400">{device.temp}°C</p>
                  <p className="text-xs text-slate-500">{device.timestamp}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 flex flex-col justify-center items-center text-center space-y-4">
          <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center text-emerald-400">
            <ICONS.Code />
          </div>
          <h3 className="text-xl font-bold text-white">Expand your network</h3>
          <p className="text-slate-400 max-w-sm">
            You can add up to 255 ESP32 nodes to this system without any changes to the architecture.
          </p>
          <button className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg shadow-emerald-500/20">
            Add New Node
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-950">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 p-8 overflow-y-auto max-w-7xl mx-auto w-full">
        {activeTab === 'dashboard' && renderDashboard()}
        {activeTab === 'guide' && <ArchitectureGuide />}
        {activeTab === 'devices' && (
