import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import { ICONS } from './constants';
import { SensorData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [expandedRoom, setExpandedRoom] = useState<string | null>(null);

  // Initialize the 7 specialized nodes
  const [nodes, setNodes] = useState<Record<string, SensorData>>({
    'External Surveillance': { id: 'NODE-01', room: 'External Surveillance', presence: false, rfStatus: 'clear', systemHealth: 98, timestamp: '' },
    'Main Entry': { id: 'NODE-02', room: 'Main Entry', presence: true, distance: 2.4, speed: 0.5, heartRate: 72, breathingRate: 16, systemHealth: 99, timestamp: '' },
    'Perimeter Zone A': { id: 'NODE-03', room: 'Perimeter Zone A', presence: false, distance: 0, speed: 0, heartRate: 0, breathingRate: 0, systemHealth: 95, timestamp: '' },
    'Perimeter Zone B': { id: 'NODE-04', room: 'Perimeter Zone B', presence: false, distance: 0, speed: 0, heartRate: 0, breathingRate: 0, systemHealth: 96, timestamp: '' },
    'Arms Storage': { id: 'NODE-05', room: 'Arms Storage', presence: false, temp: 18.5, humidity: 35, heartRate: 0, systemHealth: 100, timestamp: '' },
    'Jammer Area': { id: 'NODE-06', room: 'Jammer Area', presence: false, temp: 32.1, voltage: 230.4, current: 4.2, systemHealth: 92, timestamp: '' },
    'Control Room': { id: 'NODE-07', room: 'Control Room', presence: true, temp: 22.0, heartRate: 68, breathingRate: 14, systemHealth: 99, timestamp: '' },
  });

  // Simulation loop
  useEffect(() => {
    const interval = setInterval(() => {
      setNodes(prev => {
        const next = { ...prev };
        const now = new Date().toLocaleTimeString();

        Object.keys(next).forEach(key => {
          const node = next[key];
          next[key] = {
            ...node,
            timestamp: now,
            // Dynamic shifts for bio-metrics if presence is true
            heartRate: node.presence ? Math.floor(65 + Math.random() * 15) : 0,
            breathingRate: node.presence ? Math.floor(12 + Math.random() * 6) : 0,
            // Randomly toggle presence in perimeter for simulation
            presence: key.includes('Perimeter') ? Math.random() > 0.95 : node.presence,
            // Voltage fluctuations
            voltage: node.voltage ? +(node.voltage + (Math.random() - 0.5)).toFixed(1) : undefined,
          };
        });
        return next;
      });
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const toggleRoom = (room: string) => {
    setExpandedRoom(expandedRoom === room ? null : room);
  };

  const renderNodeDetails = (node: SensorData) => (
    <div className="mt-4 grid grid-cols-2 md:grid-cols-4 gap-4 animate-in slide-in-from-top-4 duration-300">
      {/* MR02BHA Biometrics */}
      {(node.heartRate !== undefined || node.breathingRate !== undefined) && (
        <>
          <div className="bg-black/40 border border-slate-800 p-4 rounded-xl">
            <div className="flex items-center gap-2 text-rose-500 mb-1">
              <ICONS.Heart /> <span className="text-[10px] font-bold uppercase">Heart Rate</span>
            </div>
            <div className="text-xl font-black italic">{node.heartRate || '--'} <span className="text-[10px] not-italic text-slate-500">BPM</span></div>
          </div>
          <div className="bg-black/40 border border-slate-800 p-4 rounded-xl">
            <div className="flex items-center gap-2 text-cyan-500 mb-1">
              <ICONS.Activity /> <span className="text-[10px] font-bold uppercase">Breathing</span>
            </div>
            <div className="text-xl font-black italic">{node.breathingRate || '--'} <span className="text-[10px] not-italic text-slate-500">RPM</span></div>
          </div>
        </>
      )}

      {/* Environmentals */}
      {node.temp !== undefined && (
        <div className="bg-black/40 border border-slate-800 p-4 rounded-xl">
          <div className="flex items-center gap-2 text-emerald-500 mb-1">
            <ICONS.Temp /> <span className="text-[10px] font-bold uppercase">Temp</span>
          </div>
          <div className="text-xl font-black italic">{node.temp}°C</div>
        </div>
      )}

      {/* Electrical (Node 6) */}
      {node.voltage !== undefined && (
        <div className="bg-black/40 border border-slate-800 p-4 rounded-xl">
          <div className="flex items-center gap-2 text-yellow-500 mb-1">
            <ICONS.Zap /> <span className="text-[10px] font-bold uppercase">Line Voltage</span>
          </div>
          <div className="text-xl font-black italic">{node.voltage}V</div>
        </div>
      )}

      {/* Distance/Speed */}
      {node.distance !== undefined && (
        <div className="bg-black/40 border border-slate-800 p-4 rounded-xl">
          <div className="flex items-center gap-2 text-slate-400 mb-1">
            <ICONS.Shield /> <span className="text-[10px] font-bold uppercase">Proximity</span>
          </div>
          <div className="text-xl font-black italic">{node.distance}m</div>
        </div>
      )}
    </div>
  );

  return (
    <div className="flex min-h-screen bg-black text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 p-8 overflow-y-auto">
        <header className="mb-10 flex justify-between items-end">
          <div>
            <h1 className="text-5xl font-black italic uppercase tracking-tighter text-white">Sentinel_Command</h1>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-[0.3em] mt-2">Strategic Infrastructure Overview // 7 Nodes Active</p>
          </div>
          <div className="flex gap-4">
            <div className="bg-slate-900/50 border border-slate-800 px-4 py-2 rounded-lg">
               <span className="text-[10px] font-bold text-slate-500 uppercase block">Global Health</span>
               <span className="text-emerald-500 font-mono font-bold">97.4%</span>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 gap-4">
          {Object.values(nodes).map((node) => {
            const isCritical = node.presence && (node.room.includes('Perimeter') || node.room === 'Arms Storage');
            const isExpanded = expandedRoom === node.room;

            return (
              <div 
                key={node.id}
                className={`group border transition-all duration-300 rounded-[2rem] overflow-hidden ${
                  isCritical 
                  ? 'border-red-500/50 bg-red-500/5 shadow-[0_0_40px_rgba(239,68,68,0.1)]' 
                  : isExpanded 
                    ? 'border-emerald-500/30 bg-slate-900/40' 
                    : 'border-slate-800 bg-slate-900/20 hover:border-slate-700'
                }`}
              >
                <div 
                  className="p-6 cursor-pointer flex items-center justify-between"
                  onClick={() => toggleRoom(node.room)}
                >
                  <div className="flex items-center gap-6">
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-colors ${
                      node.presence ? 'bg-red-500/20 text-red-500' : 'bg-slate-950 text-slate-500'
                    }`}>
                      {node.room === 'External Surveillance' ? <ICONS.Camera /> : 
                       node.room.includes('Jammer') ? <ICONS.Radio /> :
                       <ICONS.Shield />}
                    </div>
                    <div>
                      <div className="flex items-center gap-3">
                        <h3 className="text-xl font-black italic uppercase tracking-tight text-white">{node.room}</h3>
                        <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded ${
                          node.presence ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-800 text-slate-500'
                        }`}>
                          {node.presence ? 'Presence Detected' : 'Secure'}
                        </span>
                      </div>
                      <p className="text-[10px] font-mono text-slate-600 uppercase font-bold mt-1">
                        UID: {node.id} // HW: ESP32_V4 // RF: {node.rfStatus || 'N/A'}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-8">
                    <div className="hidden md:block text-right">
                      <p className="text-[10px] font-black text-slate-500 uppercase">System Integrity</p>
                      <div className="w-24 h-1.5 bg-slate-800 rounded-full mt-1 overflow-hidden">
                        <div className="h-full bg-emerald-500" style={{ width: `${node.systemHealth}%` }}></div>
                      </div>
                    </div>
                    <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-90' : ''}`}>
                      <ICONS.ChevronRight />
                    </div>
                  </div>
                </div>

                {isExpanded && (
                  <div className="px-6 pb-8 border-t border-slate-800/50 pt-4">
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Tactical Telemetry Data</h4>
                      <span className="text-[10px] font-mono text-slate-500 italic">Last Sync: {node.timestamp}</span>
                    </div>

                    {/* Visual Feed Placeholder for Camera Nodes */}
                    {(node.room === 'External Surveillance' || node.room === 'Main Entry') && (
                      <div className="w-full h-48 bg-black rounded-2xl mb-6 border border-slate-800 flex flex-col items-center justify-center relative overflow-hidden group/cam">
                         <div className="absolute top-4 left-4 flex items-center gap-2 bg-red-600 px-2 py-1 rounded text-[10px] font-bold text-white uppercase animate-pulse">
                           <div className="w-1.5 h-1.5 rounded-full bg-white"></div> Live
                         </div>
                         <ICONS.Camera />
                         <span className="text-[10px] font-black text-slate-700 uppercase mt-2 tracking-widest">Encrypted Stream Protocol 102.4</span>
                         <div className="absolute bottom-0 inset-x-0 h-1 bg-emerald-500/20">
                            <div className="h-full bg-emerald-500 animate-scan"></div>
                         </div>
                      </div>
                    )}

                    {renderNodeDetails(node)}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </main>

      <style>{`
        @keyframes scan {
          0% { width: 0%; left: 0%; }
          50% { width: 40%; left: 30%; }
          100% { width: 0%; left: 100%; }
        }
        .animate-scan {
          animation: scan 3s infinite linear;
          position: absolute;
        }
      `}</style>
    </div>
  );
};

export default App;

