      id: 'NODE-01',
      name: 'Outside Perimeter',
      status: 'ONLINE',
      systemHealth: 98,
      lastUpdate: 'Just now',
      metrics: [
        { label: 'LPDA Gain', value: 12.4, unit: 'dBi' },
        { label: 'RF Noise', value: -92, unit: 'dBm' }
      ]
    },
    {
      id: 'NODE-02',
      name: 'Main Entry',
      status: 'ONLINE',
      systemHealth: 99,
      lastUpdate: 'Just now',
      metrics: [
        { label: 'Heart Rate', value: 72, unit: 'BPM' },
        { label: 'Breath Rate', value: 16, unit: 'RPM' }
      ]
    },
    {
      id: 'NODE-03',
      name: 'Ammunition Room',
      status: 'ONLINE',
      systemHealth: 100,
      lastUpdate: 'Just now',
      metrics: [
        { label: 'Temp', value: 24.2, unit: '°C' },
        { label: 'Smoke', value: 12, unit: 'PPM' }
      ]
    },
    {
      id: 'NODE-04',
      name: 'Command Room',
      status: 'ONLINE',
      systemHealth: 97,
      lastUpdate: 'Just now',
      metrics: [
        { label: 'CPU Temp', value: 42, unit: '°C' },
        { label: 'RAM Usage', value: 14, unit: '%' }
      ]
    },
    {
      id: 'NODE-05',
      name: 'Vehicle Zone',
      status: 'ONLINE',
      systemHealth: 99,
      lastUpdate: 'Just now',
      metrics: [
        { label: 'Incursion', value: 'NO', unit: '' },
        { label: 'Dist', value: 4.2, unit: 'm' }
